    "evidence": "文件: docs_src/query_params_str_validations/tutorial012_an_py310.py
@@ -6,6 +6,8 @@


 @app.get("/items/")
-async def read_items(q: Annotated[list[str], Query()] = ["foo", "bar"]):
+async def read_items(q: Annotated[list[str], Query()] = None):
+    if q is None:
+        q = []
     query_items = {"q": q}
     return query_items

